14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const living = new Set(cells.map(toKey));
16	  const neighborCounts = new Map<CellKey, number>();
17	
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const key = toKey([x + dx, y + dy]);
21	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
22	    }
23	  }
24	
25	  const next: Cell[] = [];
26	  for (const [key, count] of neighborCounts) {
27	    const alive = living.has(key);
28	    if (count === 3 || (alive && count === 2)) {
29	      next.push(fromKey(key));
30	    }
31	  }
32	  return next;
33	}
